module top_module(a, b, g_out, p_out);input a, b;
  output g_out, p_out;

  wire or_not, or_out;

  // AND gate using built-in Verilog operator
  assign or_not = a & b;

  // OR gate using built-in Verilog operator
  assign or_out = a | b;

  // Assign outputs
  assign g_out = or_not;
  assign p_out = or_out;

endmodule
